module top_module(addr_out, data_in, load, clk, rst);parameter word_size = 10;
  parameter address_size = 8;
  output reg [address_size-1: 0] 	addr_out;
  input 	[address_size-1: 0] 	data_in;
  input 			load, clk, rst;
  always @ (posedge clk or negedge rst)
    if (rst == 0) addr_out <= 0; else if (load) addr_out <= data_in;
endmodule
